datasets = [
    (materials_Europa,  'Radiation shielding at Europa — 1 day'),
    (materials_HighEcc, 'Radiation shielding — High Eccentricity Orbit — 1 orbit'),
    (materials_Science, 'Radiation shielding — Science Orbit — 1 orbit'),
]

fig, axes = plt.subplots(1, 3, figsize=(18, 6), sharey=False)
ylabels = ['Dose (rad/day)', 'Dose (rad/orbit)', 'Dose (rad/orbit)']

for ax, (materials, title), ylabel in zip(axes, datasets, ylabels):
    for name, dose in materials.items():
        ax.loglog(eq_al, dose, label=name, color=colors[name], linewidth=2)

    ax.set_xlabel('Equivalent Al thickness (cm)', fontsize=11)
    ax.set_ylabel(ylabel, fontsize=11)
    ax.set_title(title, fontsize=11)
    ax.legend(framealpha=0.9, fontsize=9)
    ax.grid(True, which='both', linestyle='--', linewidth=0.5, alpha=0.5)
    ax.set_xlim(min(eq_al), max(eq_al))
plt.tight_layout()
plt.savefig('radiation_shielding_all.png', dpi=150, bbox_inches='tight')
plt.show()